using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Gestor de missões (Etapa 5.1), no mesmo padrão singleton de
/// GameVariables/PlayerProgress (auto-criado antes da primeira cena).
///
/// Não guarda estado próprio: lê/escreve as variáveis globais bool definidas
/// em cada MissionData (StartedVariable/CompletedVariable/
/// TaskCompletedVariable por tarefa) via GameVariables.Instance. Assim,
/// qualquer Condition_BoolVariable, drop condicionado (Etapa 4.3) ou condição
/// de desactivação de inimigo (Etapa 5.4) pode reagir ao estado de uma missão
/// ou tarefa sem conhecer este manager.
///
/// Usado pelas ações de diálogo Action_StartMission/Action_CompleteMission/
/// Action_CompleteMissionTask/Action_SetMissionTaskState e pelas condições
/// Condition_MissionState/Condition_MissionTaskState (Etapas 5.2/5.3).
///
/// Tarefas não-lineares: a cada frame (Update), percorre
/// GameDatabase.Instance.missions e, para cada tarefa ACTIVA (ver
/// <see cref="IsTaskActive"/>) com "autoCompleteConditions" preenchido, conclui
/// a tarefa automaticamente se as condições passarem a verdadeiras — cobre
/// tarefas tipo "Recolhe X Sementes" sem precisar de nenhum evento de NPC.
/// </summary>
public class MissionManager : MonoBehaviour
{
    public static MissionManager Instance { get; private set; }

    /// <summary>
    /// Marca instâncias criadas automaticamente por <see cref="EnsureExists"/>
    /// antes da primeira cena carregar (ver PlayerProgress.cs para a explicação
    /// completa — Tarefa #15 "GameBootstrap e singletons").
    /// </summary>
    private bool isAutoFallback;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(MissionManager) + " (Fallback)");
        var instance = go.AddComponent<MissionManager>();
        instance.isAutoFallback = true;
    }

    // ---------------- Avaliação por eventos (Task #30) ----------------
    // Em vez de avaliar autoCompleteConditions a cada frame (Update), subscrevemos
    // eventos relevantes e avaliamos apenas quando algo muda. Cobre:
    //  - GameVariables.AnyVariableChanged — variáveis bool/int/float/string
    //  - PlayerProgress.SeedsChanged, HealthChanged, RunasChanged, StateRestored
    // O Update() foi removido; se no futuro aparecerem condições não cobertas,
    // re-adicionar com throttle (ex: a cada segundo).

    // Delegates armazenados para poder desinscrever correctamente (lambdas criam
    // instâncias diferentes a cada chamada, tornando -= ineficaz).
    private System.Action _onVarChanged;
    private System.Action<int> _onSeedsChanged;
    private System.Action<int, int> _onHealthChanged;
    private System.Action<int, int> _onRunasChanged;
    private System.Action _onStateRestored;

    private void OnEnable()
    {
        _onVarChanged     = EvaluateMissions;
        _onSeedsChanged   = _ => EvaluateMissions();
        _onHealthChanged  = (_, __) => EvaluateMissions();
        _onRunasChanged   = (_, __) => EvaluateMissions();
        _onStateRestored  = EvaluateMissions;

        var vars = GameVariables.Instance;
        if (vars != null) vars.AnyVariableChanged += _onVarChanged;

        var prog = PlayerProgress.Instance;
        if (prog != null)
        {
            prog.SeedsChanged  += _onSeedsChanged;
            prog.HealthChanged += _onHealthChanged;
            prog.RunasChanged  += _onRunasChanged;
            prog.StateRestored += _onStateRestored;
        }
    }

    private void OnDisable()
    {
        if (GameVariables.Instance != null && _onVarChanged != null)
            GameVariables.Instance.AnyVariableChanged -= _onVarChanged;

        var prog = PlayerProgress.Instance;
        if (prog != null)
        {
            if (_onSeedsChanged  != null) prog.SeedsChanged  -= _onSeedsChanged;
            if (_onHealthChanged != null) prog.HealthChanged -= _onHealthChanged;
            if (_onRunasChanged  != null) prog.RunasChanged  -= _onRunasChanged;
            if (_onStateRestored != null) prog.StateRestored -= _onStateRestored;
        }
    }

    /// <summary>
    /// Avalia todas as tarefas de missão activas com autoCompleteConditions e
    /// conclui as que satisfaçam as condições. Chamado por eventos em vez de
    /// Update() (Task #30).
    /// </summary>
    private void EvaluateMissions()
    {
        var database = GameDatabase.Instance;
        if (database?.missions == null) return;

        foreach (var mission in database.missions)
        {
            if (mission == null || mission.tasks == null) continue;
            if (!IsMissionStarted(mission) || IsMissionCompleted(mission)) continue;

            foreach (var task in mission.tasks)
            {
                if (task == null) continue;
                if (task.autoCompleteConditions == null || task.autoCompleteConditions.Count == 0) continue;
                if (!IsTaskActive(mission, task)) continue;

                if (NpcConditionUtil.EvaluateConditions(task.autoCompleteConditions, task.autoCompleteRequireAll, null))
                    CompleteTask(mission, task);
            }
        }
    }

    /// <summary>
    /// Disparado quando uma missão passa a "concluída" pela primeira vez (via
    /// <see cref="CompleteMission"/>, directamente ou automaticamente quando
    /// todas as tarefas ficam concluídas — ver <see cref="CompleteTask"/>).
    /// Usado pelo banner/música "MISSÃO CONCLUÍDA" (Sistema de Missões).
    /// </summary>
    public static event System.Action<MissionData> OnMissionCompleted;

    // Task #11: limpa subscribers ao entrar em Play Mode sem Domain Reload
    // (mesmo padrão de PlayerLocator/GamePauseUtil/WheelTimeScaleUtil).
    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.SubsystemRegistration)]
    private static void ResetStaticEvents() => OnMissionCompleted = null;

    /// <summary>Marca a missão como iniciada (escreve a variável de activação).</summary>
    public void StartMission(MissionData mission)
    {
        if (mission == null || GameVariables.Instance == null) return;
        GameVariables.Instance.SetBool(mission.StartedVariable, mission.startedValue);
    }

    /// <summary>Marca a missão como concluída (escreve a variável de conclusão), marca TODAS as tarefas como concluídas e dispara <see cref="OnMissionCompleted"/> na primeira vez.</summary>
    public void CompleteMission(MissionData mission)
    {
        if (mission == null || GameVariables.Instance == null) return;

        bool wasCompleted = IsMissionCompleted(mission);

        GameVariables.Instance.SetBool(mission.CompletedVariable, mission.completedValue);

        if (mission.tasks != null)
        {
            foreach (var task in mission.tasks)
            {
                string variable = mission.TaskCompletedVariable(task);
                if (variable != null) GameVariables.Instance.SetBool(variable, true);
            }
        }

        if (!wasCompleted && mission.completedValue)
            OnMissionCompleted?.Invoke(mission);
    }

    /// <summary>True se a variável de activação da missão tem o valor de "iniciada".</summary>
    public bool IsMissionStarted(MissionData mission)
    {
        if (mission == null || GameVariables.Instance == null) return false;
        return GameVariables.Instance.GetBool(mission.StartedVariable, !mission.startedValue) == mission.startedValue;
    }

    /// <summary>True se a variável de conclusão da missão tem o valor de "concluída".</summary>
    public bool IsMissionCompleted(MissionData mission)
    {
        if (mission == null || GameVariables.Instance == null) return false;
        return GameVariables.Instance.GetBool(mission.CompletedVariable, !mission.completedValue) == mission.completedValue;
    }

    /// <summary>True se "task" já está marcada como concluída (variável global própria — ver MissionData.TaskCompletedVariable).</summary>
    public bool IsTaskCompleted(MissionData mission, MissionTask task)
    {
        if (mission == null || task == null || GameVariables.Instance == null) return false;

        string variable = mission.TaskCompletedVariable(task);
        return variable != null && GameVariables.Instance.GetBool(variable);
    }

    /// <summary>Como <see cref="IsTaskCompleted(MissionData, MissionTask)"/>, mas pelo "Task Id" da tarefa.</summary>
    public bool IsTaskCompleted(MissionData mission, string taskId)
    {
        return IsTaskCompleted(mission, mission?.FindTask(taskId));
    }

    /// <summary>True se TODAS as "dependsOnTaskIds" de "task" já estiverem concluídas (vazio = sem pré-requisitos = true). "Task Ids" que não existam na missão são ignorados.</summary>
    public bool AreDependenciesMet(MissionData mission, MissionTask task)
    {
        if (mission == null || task == null) return false;
        if (task.dependsOnTaskIds == null || task.dependsOnTaskIds.Count == 0) return true;

        foreach (var dependencyId in task.dependsOnTaskIds)
        {
            if (string.IsNullOrEmpty(dependencyId)) continue;

            var dependency = mission.FindTask(dependencyId);
            if (dependency == null) continue; // Task Id inválido — ignora (ver avisos do Editor)

            if (!IsTaskCompleted(mission, dependency)) return false;
        }

        return true;
    }

    /// <summary>
    /// True se "task" está ACTIVA: a missão está iniciada e não concluída, a
    /// tarefa ainda não está concluída, e todas as suas dependências
    /// (<see cref="AreDependenciesMet"/>) já estão concluídas. Pode haver várias
    /// tarefas activas em simultâneo (tarefas não-lineares/paralelas).
    /// </summary>
    public bool IsTaskActive(MissionData mission, MissionTask task)
    {
        if (mission == null || task == null) return false;
        if (!IsMissionStarted(mission) || IsMissionCompleted(mission)) return false;
        if (IsTaskCompleted(mission, task)) return false;

        return AreDependenciesMet(mission, task);
    }

    /// <summary>Todas as tarefas actualmente activas desta missão (ver <see cref="IsTaskActive"/>), na ordem definida em MissionData.tasks.</summary>
    public List<MissionTask> GetActiveTasks(MissionData mission)
    {
        var result = new List<MissionTask>();
        if (mission?.tasks == null) return result;

        foreach (var task in mission.tasks)
            if (task != null && IsTaskActive(mission, task)) result.Add(task);

        return result;
    }

    /// <summary>True se a missão não tem tarefas, ou se TODAS as suas tarefas já estão concluídas.</summary>
    public bool AreAllTasksCompleted(MissionData mission)
    {
        if (mission?.tasks == null || mission.tasks.Count == 0) return true;

        foreach (var task in mission.tasks)
            if (task != null && !IsTaskCompleted(mission, task)) return false;

        return true;
    }

    /// <summary>
    /// Marca "task" como concluída (ex: ao falar com um NPC ou recolher um
    /// objecto). Se, depois disso, TODAS as tarefas da missão estiverem
    /// concluídas, a missão é concluída automaticamente (dispara
    /// <see cref="OnMissionCompleted"/> na primeira vez). Pode ser chamado
    /// mesmo que "task" ainda não estivesse activa (ex: o jogador "saltou"
    /// pré-requisitos por outro caminho de diálogo) — o estado fica gravado e a
    /// tarefa passa a aparecer como concluída no Diário.
    /// </summary>
    public void CompleteTask(MissionData mission, MissionTask task)
    {
        SetTaskCompleted(mission, task, true);
    }

    /// <summary>Como <see cref="CompleteTask(MissionData, MissionTask)"/>, mas pelo "Task Id" da tarefa. Sem efeito se "taskId" não existir na missão.</summary>
    public void CompleteTask(MissionData mission, string taskId)
    {
        SetTaskCompleted(mission, mission?.FindTask(taskId), true);
    }

    /// <summary>
    /// Define directamente o estado "concluída" de "task" (true ou false) —
    /// útil para ramos de diálogo que "saltam"/"desfazem" tarefas. Ao marcar
    /// como concluída, se TODAS as tarefas da missão ficarem concluídas, a
    /// missão é concluída automaticamente.
    /// </summary>
    public void SetTaskCompleted(MissionData mission, MissionTask task, bool completed)
    {
        if (mission == null || task == null || GameVariables.Instance == null) return;

        string variable = mission.TaskCompletedVariable(task);
        if (variable == null) return;

        GameVariables.Instance.SetBool(variable, completed);

        if (completed && AreAllTasksCompleted(mission))
            CompleteMission(mission);
    }

    /// <summary>Como <see cref="SetTaskCompleted(MissionData, MissionTask, bool)"/>, mas pelo "Task Id" da tarefa. Sem efeito se "taskId" não existir na missão.</summary>
    public void SetTaskCompleted(MissionData mission, string taskId, bool completed)
    {
        SetTaskCompleted(mission, mission?.FindTask(taskId), completed);
    }

    /// <summary>
    /// Verifica, a cada frame, todas as tarefas ACTIVAS (ver
    /// <see cref="IsTaskActive"/>) de todas as missões em
    /// GameDatabase.Instance.missions e conclui automaticamente as que tiverem
    /// "autoCompleteConditions" preenchido e cumprido (ver MissionTask). Cobre
    /// tarefas tipo "Recolhe X Sementes"/"Tens o item Y" sem nenhum evento de
    /// NPC.
    /// </summary>
}
